use bids_rust::{parse_bids_filename, BidsFile, BidsEntity};
use std::collections::HashMap;

#[test]
fn test_parse_functional_filename() {
    let filename = "sub-01_ses-pre_task-rest_run-1_bold.nii.gz";
    let result = parse_bids_filename(filename).unwrap();

    assert_eq!(result.entities.get("sub"), Some(&"01".to_string()));
    assert_eq!(result.entities.get("ses"), Some(&"pre".to_string()));
    assert_eq!(result.entities.get("task"), Some(&"rest".to_string()));
    assert_eq!(result.entities.get("run"), Some(&"1".to_string()));
    assert_eq!(result.suffix, "bold");
    assert_eq!(result.extension, "nii.gz");
}

#[test]
fn test_parse_anatomical_filename() {
    let filename = "sub-03_ses-post_T1w.nii.gz";
    let result = parse_bids_filename(filename).unwrap();

    assert_eq!(result.entities.get("sub"), Some(&"03".to_string()));
    assert_eq!(result.entities.get("ses"), Some(&"post".to_string()));
    assert_eq!(result.suffix, "T1w");
    assert_eq!(result.extension, "nii.gz");
}

#[test]
fn test_parse_fmriprep_filename() {
    let filename = "sub-01_ses-01_task-rest_space-MNI152NLin2009cAsym_desc-preproc_bold.nii.gz";
    let result = parse_bids_filename(filename).unwrap();

    assert_eq!(result.entities.get("sub"), Some(&"01".to_string()));
    assert_eq!(result.entities.get("ses"), Some(&"01".to_string()));
    assert_eq!(result.entities.get("task"), Some(&"rest".to_string()));
    assert_eq!(result.entities.get("space"), Some(&"MNI152NLin2009cAsym".to_string()));
    assert_eq!(result.entities.get("desc"), Some(&"preproc".to_string()));
    assert_eq!(result.suffix, "bold");
    assert_eq!(result.extension, "nii.gz");
}

#[test]
fn test_parse_event_filename() {
    let filename = "sub-01_task-nback_events.tsv";
    let result = parse_bids_filename(filename).unwrap();

    assert_eq!(result.entities.get("sub"), Some(&"01".to_string()));
    assert_eq!(result.entities.get("task"), Some(&"nback".to_string()));
    assert_eq!(result.suffix, "events");
    assert_eq!(result.extension, "tsv");
}

#[test]
fn test_parse_confounds_filename() {
    let filename = "sub-01_ses-pre_task-rest_desc-confounds_timeseries.tsv";
    let result = parse_bids_filename(filename).unwrap();

    assert_eq!(result.entities.get("sub"), Some(&"01".to_string()));
    assert_eq!(result.entities.get("ses"), Some(&"pre".to_string()));
    assert_eq!(result.entities.get("task"), Some(&"rest".to_string()));
    assert_eq!(result.entities.get("desc"), Some(&"confounds".to_string()));
    assert_eq!(result.suffix, "timeseries");
    assert_eq!(result.extension, "tsv");
}

#[test]
fn test_parse_json_sidecar() {
    let filename = "sub-01_task-rest_bold.json";
    let result = parse_bids_filename(filename).unwrap();

    assert_eq!(result.entities.get("sub"), Some(&"01".to_string()));
    assert_eq!(result.entities.get("task"), Some(&"rest".to_string()));
    assert_eq!(result.suffix, "bold");
    assert_eq!(result.extension, "json");
}

#[test]
fn test_bids_file_encode_decode() {
    // Create a BidsFile manually
    let mut entities = HashMap::new();
    entities.insert("sub".to_string(), "02".to_string());
    entities.insert("ses".to_string(), "retest".to_string());
    entities.insert("task".to_string(), "stroop".to_string());
    entities.insert("run".to_string(), "2".to_string());

    let bids_file = BidsFile {
        entities: entities.clone(),
        suffix: "bold".to_string(),
        extension: "nii.gz".to_string(),
        path: None,
    };

    // Encode to filename
    let encoded = bids_file.to_filename();

    // Should contain all entities in BIDS order
    assert!(encoded.starts_with("sub-02"));
    assert!(encoded.contains("ses-retest"));
    assert!(encoded.contains("task-stroop"));
    assert!(encoded.contains("run-2"));
    assert!(encoded.ends_with("_bold.nii.gz"));

    // Decode back
    let decoded = parse_bids_filename(&encoded).unwrap();
    assert_eq!(decoded.entities, entities);
    assert_eq!(decoded.suffix, "bold");
    assert_eq!(decoded.extension, "nii.gz");
}

#[test]
fn test_parse_invalid_filename() {
    // Not a BIDS filename
    let filename = "random_file.txt";
    let result = parse_bids_filename(filename);
    assert!(result.is_err());

    // Missing suffix
    let filename = "sub-01_task-rest.nii.gz";
    let result = parse_bids_filename(filename);
    assert!(result.is_err());
}

#[test]
fn test_parse_with_acq_entity() {
    let filename = "sub-01_acq-highres_T1w.nii.gz";
    let result = parse_bids_filename(filename).unwrap();

    assert_eq!(result.entities.get("sub"), Some(&"01".to_string()));
    assert_eq!(result.entities.get("acq"), Some(&"highres".to_string()));
    assert_eq!(result.suffix, "T1w");
}

#[test]
fn test_parse_with_echo_entity() {
    let filename = "sub-01_task-rest_echo-1_bold.nii.gz";
    let result = parse_bids_filename(filename).unwrap();

    assert_eq!(result.entities.get("sub"), Some(&"01".to_string()));
    assert_eq!(result.entities.get("task"), Some(&"rest".to_string()));
    assert_eq!(result.entities.get("echo"), Some(&"1".to_string()));
    assert_eq!(result.suffix, "bold");
}

#[test]
fn test_parse_dwi_filename() {
    let filename = "sub-01_acq-b1000_dwi.nii.gz";
    let result = parse_bids_filename(filename).unwrap();

    assert_eq!(result.entities.get("sub"), Some(&"01".to_string()));
    assert_eq!(result.entities.get("acq"), Some(&"b1000".to_string()));
    assert_eq!(result.suffix, "dwi");
}

#[test]
fn test_entity_ordering() {
    // Test that entities are ordered correctly when encoding
    let mut entities = HashMap::new();
    entities.insert("run".to_string(), "1".to_string());
    entities.insert("task".to_string(), "rest".to_string());
    entities.insert("ses".to_string(), "01".to_string());
    entities.insert("sub".to_string(), "01".to_string());

    let bids_file = BidsFile {
        entities,
        suffix: "bold".to_string(),
        extension: "nii.gz".to_string(),
        path: None,
    };

    let filename = bids_file.to_filename();

    // Check order: sub should come before ses, ses before task, task before run
    let sub_pos = filename.find("sub-01").unwrap();
    let ses_pos = filename.find("ses-01").unwrap();
    let task_pos = filename.find("task-rest").unwrap();
    let run_pos = filename.find("run-1").unwrap();

    assert!(sub_pos < ses_pos);
    assert!(ses_pos < task_pos);
    assert!(task_pos < run_pos);
}

