        .execute()
        .unwrap();

    // All files should be from ses-01
    for file in &files {
        assert!(file.entities.get("ses").map(|s| s == "01").unwrap_or(false));
    }
}

#[test]
fn test_search_by_task() {
    let (_temp_dir, project) = create_test_bids_project();

    let rest_files = project.search_files()
