        }
    }
}

#[test]
fn test_search_by_run() {
    let (_temp_dir, project) = create_test_bids_project();

    let run1_files = project.search_files()
        .run("1")
        .execute()
        .unwrap();

    for file in &run1_files {
        if file.entities.contains_key("run") {
            assert_eq!(file.entities.get("run").unwrap(), "1");
        }
