}

#[test]
fn test_search_by_suffix() {
    let (_temp_dir, project) = create_test_bids_project();

    let bold_files = project.search_files()
        .suffix("bold")
        .execute()
        .unwrap();

    for file in &bold_files {
        assert_eq!(file.suffix, "bold");
