        .unwrap();

    for file in &json_files {
        assert_eq!(file.extension, "json");
    }
}

#[test]
fn test_search_combined_filters() {
    let (_temp_dir, project) = create_test_bids_project();

    // Search for sub-01, ses-01, bold files
    let files = project.search_files()
        .subject("01")
