    let (_temp_dir, project) = create_test_bids_project();

    // Search for all T1w and T2w files
    let files = project.search_files()
        .regex(r"T[12]w")
        .execute()
        .unwrap();

    for file in &files {
        assert!(file.suffix == "T1w" || file.suffix == "T2w");
    }
}

#[test]
fn test_search_event_files() {
