use bids_rust::{BidsProject, ComplianceChecker, ComplianceSeverity};
use std::fs;
use tempfile::TempDir;

fn create_valid_bids_project() -> (TempDir, BidsProject) {
    let temp_dir = TempDir::new().unwrap();
    let root_path = temp_dir.path();

    // Create required files
    let dataset_desc = r#"{
        "Name": "Valid Dataset",
        "BIDSVersion": "1.6.0",
        "License": "CC0",
        "Authors": ["Test Author"],
        "Acknowledgements": "Test acknowledgements",
        "HowToAcknowledge": "Please cite...",
        "Funding": ["Test Grant"],
        "DatasetDOI": "10.1234/test"
    }"#;
    fs::write(root_path.join("dataset_description.json"), dataset_desc).unwrap();

    // Create README
    fs::write(root_path.join("README"), "This is a test dataset\n").unwrap();

    // Create participants.tsv
    let participants = "participant_id\tage\tsex\n\
        sub-01\t25\tM\n\
        sub-02\t30\tF\n";
    fs::write(root_path.join("participants.tsv"), participants).unwrap();

    // Create participants.json
    let participants_json = r#"{
        "participant_id": {
            "Description": "Unique participant identifier"
        },
        "age": {
            "Description": "Age in years",
            "Units": "years"
        },
        "sex": {
            "Description": "Biological sex",
            "Levels": {
                "M": "Male",
                "F": "Female"
            }
        }
    }"#;
    fs::write(root_path.join("participants.json"), participants_json).unwrap();

    // Create valid BIDS structure
    fs::create_dir_all(root_path.join("sub-01/func")).unwrap();
    fs::create_dir_all(root_path.join("sub-01/anat")).unwrap();
    fs::create_dir_all(root_path.join("sub-02/func")).unwrap();

    // Create properly named files
    fs::write(
        root_path.join("sub-01/func/sub-01_task-rest_bold.nii.gz"),
        b"dummy"
    ).unwrap();
    fs::write(
        root_path.join("sub-01/func/sub-01_task-rest_bold.json"),
        r#"{"RepetitionTime": 2.0, "TaskName": "Resting State"}"#
    ).unwrap();
    fs::write(
        root_path.join("sub-01/anat/sub-01_T1w.nii.gz"),
        b"dummy"
    ).unwrap();
    fs::write(
        root_path.join("sub-02/func/sub-02_task-rest_bold.nii.gz"),
        b"dummy"
    ).unwrap();

    let project = BidsProject::new(root_path).unwrap();
    (temp_dir, project)
}

fn create_invalid_bids_project() -> (TempDir, BidsProject) {
    let temp_dir = TempDir::new().unwrap();
    let root_path = temp_dir.path();

    // Minimal dataset_description.json (missing recommended fields)
    let dataset_desc = r#"{
        "Name": "Invalid Dataset",
        "BIDSVersion": "1.6.0"
    }"#;
    fs::write(root_path.join("dataset_description.json"), dataset_desc).unwrap();

    // No README
    // No participants.tsv

    // Create some files with issues
    fs::create_dir_all(root_path.join("sub-01/func")).unwrap();
    fs::create_dir_all(root_path.join("sub-02")).unwrap();
    fs::create_dir_all(root_path.join("sub_03/func")).unwrap(); // Wrong naming

    // Invalid filenames
    fs::write(
        root_path.join("sub-01/func/sub-01_bold.nii.gz"), // Missing task
        b"dummy"
    ).unwrap();
    fs::write(
        root_path.join("sub-01/func/sub-01_task-rest.nii.gz"), // Missing suffix
        b"dummy"
    ).unwrap();
    fs::write(
        root_path.join("sub-01/func/sub-01_task_rest_bold.nii.gz"), // Underscore instead of dash
        b"dummy"
    ).unwrap();

    // Orphaned sidecar
    fs::write(
        root_path.join("sub-02/sub-02_task-nback_bold.json"),
        r#"{"RepetitionTime": 2.0}"#
    ).unwrap();

    let project = BidsProject::new(root_path).unwrap();
    (temp_dir, project)
}

#[test]
fn test_valid_bids_compliance() {
    let (_temp_dir, project) = create_valid_bids_project();

    let checker = ComplianceChecker::new(&project);
    let result = checker.check_compliance().unwrap();

    // Should pass with only warnings (if any)
    assert!(result.is_valid);

    // Check that we have no errors
    let errors: Vec<_> = result.issues.iter()
        .filter(|i| i.severity == ComplianceSeverity::Error)
        .collect();
    assert_eq!(errors.len(), 0);
}

#[test]
fn test_dataset_description_compliance() {
    let temp_dir = TempDir::new().unwrap();
    let root_path = temp_dir.path();

    // Missing dataset_description.json
    let result = BidsProject::new(root_path);
    assert!(result.is_err());

    // Invalid JSON
    fs::write(root_path.join("dataset_description.json"), "invalid json").unwrap();
    let result = BidsProject::new(root_path);
    assert!(result.is_err());

    // Missing required fields
    let dataset_desc = r#"{
        "Name": "Test"
    }"#; // Missing BIDSVersion
    fs::write(root_path.join("dataset_description.json"), dataset_desc).unwrap();
    let result = BidsProject::new(root_path);
    assert!(result.is_err());
}

#[test]
fn test_filename_compliance() {
    let (_temp_dir, project) = create_invalid_bids_project();

    let checker = ComplianceChecker::new(&project);
    let result = checker.check_compliance().unwrap();

    // Should have errors
    assert!(!result.is_valid);

    let errors: Vec<_> = result.issues.iter()
        .filter(|i| i.severity == ComplianceSeverity::Error)
        .collect();
    assert!(errors.len() > 0);

    // Check for specific error types
    let invalid_names: Vec<_> = errors.iter()
        .filter(|i| i.description.contains("Invalid BIDS filename"))
        .collect();
    assert!(invalid_names.len() > 0);
}

#[test]
fn test_required_files_compliance() {
    let (_temp_dir, project) = create_invalid_bids_project();

    let checker = ComplianceChecker::new(&project);
    let result = checker.check_compliance().unwrap();

    // Check for missing README warning
    let readme_warnings: Vec<_> = result.issues.iter()
        .filter(|i| i.description.contains("README"))
        .collect();
    assert!(readme_warnings.len() > 0);

    // Check for missing participants.tsv warning
    let participants_warnings: Vec<_> = result.issues.iter()
        .filter(|i| i.description.contains("participants.tsv"))
        .collect();
    assert!(participants_warnings.len() > 0);
}

#[test]
fn test_orphaned_files_compliance() {
    let (_temp_dir, project) = create_invalid_bids_project();

    let checker = ComplianceChecker::new(&project);
    let result = checker.check_compliance().unwrap();

    // Check for orphaned sidecar warning
    let orphan_warnings: Vec<_> = result.issues.iter()
        .filter(|i| i.description.contains("orphaned"))
        .collect();
    assert!(orphan_warnings.len() > 0);
}

#[test]
fn test_subject_consistency() {
    let temp_dir = TempDir::new().unwrap();
    let root_path = temp_dir.path();

    // Create dataset_description.json
    let dataset_desc = r#"{
        "Name": "Consistency Test",
        "BIDSVersion": "1.6.0"
    }"#;
    fs::write(root_path.join("dataset_description.json"), dataset_desc).unwrap();

    // Create participants.tsv with sub-01 and sub-02
    let participants = "participant_id\n\
        sub-01\n\
        sub-02\n";
    fs::write(root_path.join("participants.tsv"), participants).unwrap();

    // Create data for sub-01, sub-02, and sub-03 (not in participants.tsv)
    fs::create_dir_all(root_path.join("sub-01/func")).unwrap();
    fs::create_dir_all(root_path.join("sub-02/func")).unwrap();
    fs::create_dir_all(root_path.join("sub-03/func")).unwrap();

    fs::write(
        root_path.join("sub-01/func/sub-01_task-rest_bold.nii.gz"),
        b"dummy"
    ).unwrap();
    fs::write(
        root_path.join("sub-03/func/sub-03_task-rest_bold.nii.gz"),
        b"dummy"
    ).unwrap();

    let project = BidsProject::new(root_path).unwrap();
    let checker = ComplianceChecker::new(&project);
    let result = checker.check_compliance().unwrap();

    // Should have warning about sub-03 not in participants.tsv
    let consistency_warnings: Vec<_> = result.issues.iter()
        .filter(|i| i.description.contains("sub-03") && i.description.contains("participants.tsv"))
        .collect();
    assert!(consistency_warnings.len() > 0);
}

#[test]
fn test_task_consistency() {
    let temp_dir = TempDir::new().unwrap();
    let root_path = temp_dir.path();

    // Create dataset_description.json
    let dataset_desc = r#"{
        "Name": "Task Test",
        "BIDSVersion": "1.6.0"
    }"#;
    fs::write(root_path.join("dataset_description.json"), dataset_desc).unwrap();

    fs::create_dir_all(root_path.join("sub-01/func")).unwrap();

    // Create functional scan without corresponding events file
    fs::write(
        root_path.join("sub-01/func/sub-01_task-memory_bold.nii.gz"),
        b"dummy"
    ).unwrap();

    // Create functional scan with sidecar but missing TaskName
    fs::write(
        root_path.join("sub-01/func/sub-01_task-memory_bold.json"),
        r#"{"RepetitionTime": 2.0}"# // Missing TaskName
    ).unwrap();

    let project = BidsProject::new(root_path).unwrap();
    let checker = ComplianceChecker::new(&project);
    let result = checker.check_compliance().unwrap();

    // Should have warning about missing TaskName
    let task_warnings: Vec<_> = result.issues.iter()
        .filter(|i| i.description.contains("TaskName"))
        .collect();
    assert!(task_warnings.len() > 0);
}

#[test]
fn test_compliance_summary() {
    let (_temp_dir, project) = create_valid_bids_project();

    let checker = ComplianceChecker::new(&project);
    let result = checker.check_compliance().unwrap();

    // Get summary
    let summary = result.summary();

    assert!(summary.contains("BIDS Compliance Check"));
    assert!(summary.contains("Valid:"));

    if result.is_valid {
        assert!(summary.contains("Valid: ✓"));
    } else {
        assert!(summary.contains("Valid: ✗"));
    }
}

