use bids_rust::{BidsProject, parse_bids_filename};
use std::fs;
use tempfile::TempDir;

fn create_project_with_derivatives() -> (TempDir, BidsProject) {
    let temp_dir = TempDir::new().unwrap();
    let root_path = temp_dir.path();

    // Create dataset_description.json
    let dataset_desc = r#"{
        "Name": "Derivatives Test Dataset",
        "BIDSVersion": "1.6.0"
    }"#;
    fs::write(root_path.join("dataset_description.json"), dataset_desc).unwrap();

    // Create raw data structure
    fs::create_dir_all(root_path.join("sub-01/ses-pre/func")).unwrap();
    fs::create_dir_all(root_path.join("sub-01/ses-pre/anat")).unwrap();
    fs::create_dir_all(root_path.join("sub-01/ses-post/func")).unwrap();
    fs::create_dir_all(root_path.join("sub-02/ses-pre/func")).unwrap();

    // Create raw functional files
    fs::write(
        root_path.join("sub-01/ses-pre/func/sub-01_ses-pre_task-rest_bold.nii.gz"),
        b"dummy"
    ).unwrap();
    fs::write(
        root_path.join("sub-01/ses-pre/func/sub-01_ses-pre_task-nback_run-1_bold.nii.gz"),
        b"dummy"
    ).unwrap();
    fs::write(
        root_path.join("sub-01/ses-pre/anat/sub-01_ses-pre_T1w.nii.gz"),
        b"dummy"
    ).unwrap();

    // Create fMRIPrep derivatives
    let fmriprep_path = root_path.join("derivatives/fmriprep");
    fs::create_dir_all(fmriprep_path.join("sub-01/ses-pre/func")).unwrap();
    fs::create_dir_all(fmriprep_path.join("sub-01/ses-pre/anat")).unwrap();

    // fMRIPrep dataset_description.json
    let fmriprep_desc = r#"{
        "Name": "fMRIPrep - fMRI PREProcessing workflow",
        "BIDSVersion": "1.6.0",
        "PipelineDescription": {
            "Name": "fMRIPrep",
            "Version": "20.2.3"
        },
        "GeneratedBy": [{
            "Name": "fMRIPrep",
            "Version": "20.2.3"
        }]
    }"#;
    fs::write(fmriprep_path.join("dataset_description.json"), fmriprep_desc).unwrap();

    // Preprocessed functional files
    fs::write(
        fmriprep_path.join("sub-01/ses-pre/func/sub-01_ses-pre_task-rest_space-MNI152NLin2009cAsym_desc-preproc_bold.nii.gz"),
        b"dummy"
    ).unwrap();
    fs::write(
        fmriprep_path.join("sub-01/ses-pre/func/sub-01_ses-pre_task-rest_space-MNI152NLin2009cAsym_desc-brain_mask.nii.gz"),
        b"dummy"
    ).unwrap();
    fs::write(
        fmriprep_path.join("sub-01/ses-pre/func/sub-01_ses-pre_task-rest_desc-confounds_timeseries.tsv"),
        "trans_x\ttrans_y\ttrans_z\trot_x\trot_y\trot_z\n0.1\t0.2\t0.3\t0.01\t0.02\t0.03\n"
    ).unwrap();
    fs::write(
        fmriprep_path.join("sub-01/ses-pre/func/sub-01_ses-pre_task-rest_desc-confounds_timeseries.json"),
        r#"{"trans_x": {"Description": "Translation along x-axis"}}"#
    ).unwrap();

    // Preprocessed anatomical files
    fs::write(
        fmriprep_path.join("sub-01/ses-pre/anat/sub-01_ses-pre_space-MNI152NLin2009cAsym_desc-preproc_T1w.nii.gz"),
        b"dummy"
    ).unwrap();
    fs::write(
        fmriprep_path.join("sub-01/ses-pre/anat/sub-01_ses-pre_space-MNI152NLin2009cAsym_desc-brain_mask.nii.gz"),
        b"dummy"
    ).unwrap();

    // Multiple spaces
    fs::write(
        fmriprep_path.join("sub-01/ses-pre/func/sub-01_ses-pre_task-rest_space-T1w_desc-preproc_bold.nii.gz"),
        b"dummy"
    ).unwrap();

    // Multiple resolutions
    fs::write(
        fmriprep_path.join("sub-01/ses-pre/func/sub-01_ses-pre_task-rest_space-MNI152NLin2009cAsym_res-2_desc-preproc_bold.nii.gz"),
        b"dummy"
    ).unwrap();

    let project = BidsProject::new(root_path).unwrap();
    (temp_dir, project)
}

#[test]
fn test_detect_derivatives() {
    let (_temp_dir, project) = create_project_with_derivatives();

    assert!(project.has_derivatives);
}

#[test]
fn test_search_preprocessed_files() {
    let (_temp_dir, project) = create_project_with_derivatives();

    // Search for preprocessed files
    let preproc_files = project.search_files()
        .entity("desc", "preproc")
        .execute()
        .unwrap();

    assert!(preproc_files.len() > 0);

    // All should have desc-preproc
    for file in &preproc_files {
        assert_eq!(file.entities.get("desc"), Some(&"preproc".to_string()));
    }
}

#[test]
fn test_search_by_space() {
    let (_temp_dir, project) = create_project_with_derivatives();

    // Search for MNI space files
    let mni_files = project.search_files()
        .entity("space", "MNI152NLin2009cAsym")
        .execute()
        .unwrap();

    assert!(mni_files.len() > 0);

    for file in &mni_files {
        assert_eq!(file.entities.get("space"), Some(&"MNI152NLin2009cAsym".to_string()));
    }

    // Search for T1w space files
    let t1w_files = project.search_files()
        .entity("space", "T1w")
        .execute()
        .unwrap();

    assert!(t1w_files.len() > 0);

    for file in &t1w_files {
        assert_eq!(file.entities.get("space"), Some(&"T1w".to_string()));
    }
}

#[test]
fn test_search_brain_masks() {
    let (_temp_dir, project) = create_project_with_derivatives();

    let mask_files = project.search_files()
        .entity("desc", "brain")
        .suffix("mask")
        .execute()
        .unwrap();

    assert!(mask_files.len() > 0);

    for file in &mask_files {
        assert_eq!(file.entities.get("desc"), Some(&"brain".to_string()));
        assert_eq!(file.suffix, "mask");
    }
}

#[test]
fn test_search_confounds() {
    let (_temp_dir, project) = create_project_with_derivatives();

    let confound_files = project.search_files()
        .entity("desc", "confounds")
        .suffix("timeseries")
        .execute()
        .unwrap();

    assert!(confound_files.len() > 0);

    for file in &confound_files {
        assert_eq!(file.entities.get("desc"), Some(&"confounds".to_string()));
        assert_eq!(file.suffix, "timeseries");
    }
}

#[test]
fn test_parse_fmriprep_filenames() {
    // Test various fMRIPrep output filenames
    let filenames = vec![
        "sub-01_ses-pre_task-rest_space-MNI152NLin2009cAsym_desc-preproc_bold.nii.gz",
        "sub-01_ses-pre_task-rest_space-MNI152NLin2009cAsym_desc-brain_mask.nii.gz",
        "sub-01_ses-pre_task-rest_space-T1w_desc-preproc_bold.nii.gz",
        "sub-01_ses-pre_task-rest_space-MNI152NLin2009cAsym_res-2_desc-preproc_bold.nii.gz",
        "sub-01_ses-pre_space-MNI152NLin2009cAsym_desc-preproc_T1w.nii.gz",
        "sub-01_ses-pre_desc-confounds_timeseries.tsv",
    ];

    for filename in filenames {
        let parsed = parse_bids_filename(filename).unwrap();

        // Check common entities
        assert_eq!(parsed.entities.get("sub"), Some(&"01".to_string()));
        assert_eq!(parsed.entities.get("ses"), Some(&"pre".to_string()));

        // Check that all entities are parsed
        if filename.contains("space-") {
            assert!(parsed.entities.contains_key("space"));
        }
        if filename.contains("desc-") {
            assert!(parsed.entities.contains_key("desc"));
        }
        if filename.contains("res-") {
            assert!(parsed.entities.contains_key("res"));
        }
    }
}

#[test]
fn test_search_by_resolution() {
    let (_temp_dir, project) = create_project_with_derivatives();

    let res2_files = project.search_files()
        .entity("res", "2")
        .execute()
        .unwrap();

    assert!(res2_files.len() > 0);

    for file in &res2_files {
        assert_eq!(file.entities.get("res"), Some(&"2".to_string()));
    }
}

#[test]
fn test_derivatives_with_multiple_pipelines() {
    let temp_dir = TempDir::new().unwrap();
    let root_path = temp_dir.path();

    // Create dataset_description.json
    let dataset_desc = r#"{
        "Name": "Multi Pipeline Test",
        "BIDSVersion": "1.6.0"
    }"#;
    fs::write(root_path.join("dataset_description.json"), dataset_desc).unwrap();

    // Create raw data
    fs::create_dir_all(root_path.join("sub-01/func")).unwrap();
    fs::write(
        root_path.join("sub-01/func/sub-01_task-rest_bold.nii.gz"),
        b"dummy"
    ).unwrap();

    // Create multiple derivative pipelines
    let pipelines = vec!["fmriprep", "mriqc", "xcpengine"];

    for pipeline in pipelines {
        let pipeline_path = root_path.join(format!("derivatives/{}", pipeline));
        fs::create_dir_all(pipeline_path.join("sub-01/func")).unwrap();

        let pipeline_desc = format!(r#"{{
            "Name": "{}",
            "BIDSVersion": "1.6.0",
            "PipelineDescription": {{
                "Name": "{}"
            }}
        }}"#, pipeline, pipeline);

        fs::write(
            pipeline_path.join("dataset_description.json"),
            pipeline_desc
        ).unwrap();

        // Create pipeline-specific output
        fs::write(
            pipeline_path.join(format!("sub-01/func/sub-01_task-rest_desc-{}_bold.nii.gz", pipeline)),
            b"dummy"
        ).unwrap();
    }

    let project = BidsProject::new(root_path).unwrap();

    // Should detect derivatives
    assert!(project.has_derivatives);

    // Should find files from all pipelines
    for pipeline in vec!["fmriprep", "mriqc", "xcpengine"] {
        let pipeline_files = project.search_files()
            .entity("desc", pipeline)
            .execute()
            .unwrap();

        assert!(pipeline_files.len() > 0);
    }
}

