        b"dummy"
    ).unwrap();

    let project = BidsProject::new(root_path).unwrap();
    let summary = project.summary();

    assert_eq!(summary.name, "Summary Test Dataset");
    assert_eq!(summary.n_participants, 2);
    assert_eq!(summary.n_sessions, 2);
    assert_eq!(summary.n_runs, 0); // No explicit runs in our test data
    assert_eq!(summary.tasks.len(), 2);
    assert!(summary.tasks.contains(&"rest".to_string()));
    assert!(summary.tasks.contains(&"nback".to_string()));
    assert!(summary.modalities.contains(&"func".to_string()));
    assert!(summary.modalities.contains(&"anat".to_string()));
}

