fn test_bids_project_detect_sessions() {
    // R equivalent: test_that("sessions are detected correctly")
    let temp_dir = TempDir::new().unwrap();
    let root = temp_dir.path();

    fs::create_dir_all(root.join("sub-01/ses-01/func")).unwrap();
    fs::create_dir_all(root.join("sub-01/ses-02/func")).unwrap();
    fs::write(root.join("dataset_description.json"), r#"{"Name": "Test", "BIDSVersion": "1.6.0"}"#).unwrap();

    let project = BidsProject::new(root).unwrap();
    assert!(project.has_sessions);

    let sessions = project.get_sessions("sub-01");
    assert_eq!(sessions.len(), 2);
}

