    assert_eq!(result.entities.get("sub"), Some(&"03".to_string()));
    assert_eq!(result.entities.get("ses"), Some(&"post".to_string()));
    assert_eq!(result.suffix, "T1w");
    assert_eq!(result.extension, "nii.gz");
}

