#[test]
fn test_bids_file_encode_decode() {
    // Create a BidsFile manually
    let mut entities = HashMap::new();
    entities.insert("sub".to_string(), "02".to_string());
    entities.insert("ses".to_string(), "retest".to_string());
    entities.insert("task".to_string(), "stroop".to_string());
    entities.insert("run".to_string(), "2".to_string());

    let bids_file = BidsFile {
        entities: entities.clone(),
        suffix: "bold".to_string(),
        extension: "nii.gz".to_string(),
        path: None,
    };

    // Encode to filename
    let encoded = bids_file.to_filename();

    // Should contain all entities in BIDS order
    assert!(encoded.starts_with("sub-02"));
    assert!(encoded.contains("ses-retest"));
    assert!(encoded.contains("task-stroop"));
    assert!(encoded.contains("run-2"));
    assert!(encoded.ends_with("_bold.nii.gz"));

    // Decode back
    let decoded = parse_bids_filename(&encoded).unwrap();
    assert_eq!(decoded.entities, entities);
    assert_eq!(decoded.suffix, "bold");
    assert_eq!(decoded.extension, "nii.gz");
}

