#[test]
fn test_event_file_reading_basic() -> Result<()> {
    // Create mock dataset
    let temp_dir = MockBidsBuilder::new("event_test")
        .add_participant(Participant {
            id: "sub-01".to_string(),
            age: Some(25),
            sex: Some("M".to_string()),
            handedness: Some("R".to_string()),
        })
        .add_file(FileSpec {
            subject: "01".to_string(),
            session: None,
            datatype: "func".to_string(),
            task: Some("stroop".to_string()),
            run: Some("01".to_string()),
            suffix: "bold".to_string(),
            extension: "nii.gz".to_string(),
            space: None,
            desc: None,
            is_derivative: false,
        })
        .add_events(
            FileSpec {
                subject: "01".to_string(),
                session: None,
                datatype: "func".to_string(),
                task: Some("stroop".to_string()),
                run: Some("01".to_string()),
                suffix: "events".to_string(),
                extension: "tsv".to_string(),
                space: None,
                desc: None,
                is_derivative: false,
            },
            EventData {
                onset: vec![0.0, 2.5, 5.0, 8.0, 10.5],
                duration: vec![2.0, 2.0, 1.5, 2.0, 1.5],
                trial_type: vec!["stimulus".to_string(), "stimulus".to_string(), 
                               "response".to_string(), "stimulus".to_string(), 
                               "response".to_string()],
            },
        )
        .build()?;

    let project = BidsProject::new(temp_dir.path())?;

    // Test reading all events
    let events = project.read_events()
        .collect()?;

    assert_eq!(events.len(), 1, "Should find one event file");
    assert_eq!(events[0].data.len(), 5, "Should have 5 events");

    // Verify event data
    assert_eq!(events[0].data[0].onset, 0.0);
    assert_eq!(events[0].data[0].duration, 2.0);
    assert_eq!(events[0].data[0].trial_type, "stimulus");

    Ok(())
}

