        b"dummy"
    ).unwrap();

    // Create confounds file
    let confounds_content = "trans_x\ttrans_y\ttrans_z\trot_x\trot_y\trot_z\tglobal_signal\tcsf\twhite_matter\n\
        0.01\t-0.02\t0.03\t0.001\t-0.002\t0.001\t100.5\t95.2\t98.7\n\
        0.02\t-0.01\t0.02\t0.002\t-0.001\t0.001\t101.2\t94.8\t99.1\n\
