#[test]
fn test_read_confounds_file() {
    let (_temp_dir, project) = create_test_project_with_data();

    // Find confounds file
    let confound_files = project.search_files()
        .entity("desc", "confounds")
        .suffix("timeseries")
        .extension("tsv")
        .execute()
        .unwrap();

    assert_eq!(confound_files.len(), 1);
    let confound_file = &confound_files[0];

    // Read confound data
    let confounds = ConfoundData::read(confound_file.path.as_ref().unwrap()).unwrap();

    // Check dimensions
    assert_eq!(confounds.n_volumes(), 5);
    assert_eq!(confounds.n_confounds(), 9);

    // Check column names
    let columns = confounds.column_names();
    assert!(columns.contains(&"trans_x".to_string()));
    assert!(columns.contains(&"rot_z".to_string()));
    assert!(columns.contains(&"global_signal".to_string()));

    // Get specific columns
    let trans_x = confounds.get_column("trans_x").unwrap();
    assert_eq!(trans_x.len(), 5);
    assert!((trans_x[0] - 0.01).abs() < 1e-6);

    let global_signal = confounds.get_column("global_signal").unwrap();
    assert!((global_signal[0] - 100.5).abs() < 1e-6);

    // Get motion parameters
    let motion_params = confounds.get_motion_parameters();
    assert_eq!(motion_params.ncols(), 6); // trans_x/y/z, rot_x/y/z
    assert_eq!(motion_params.nrows(), 5); // 5 volumes

    // Check motion parameter values
    assert!((motion_params[(0, 0)] - 0.01).abs() < 1e-6); // trans_x[0]
    assert!((motion_params[(0, 3)] - 0.001).abs() < 1e-6); // rot_x[0]
}

#[test]
fn test_confounds_pca() {
    let (_temp_dir, project) = create_test_project_with_data();

    // Find and read confounds
    let confound_files = project.search_files()
        .entity("desc", "confounds")
        .execute()
        .unwrap();

    let confounds = ConfoundData::read(confound_files[0].path.as_ref().unwrap()).unwrap();

    // Perform PCA on motion parameters
    let pca_result = confounds.pca_motion(Some(2)).unwrap();

    // Check PCA results
    assert_eq!(pca_result.n_components, 2);
    assert_eq!(pca_result.components.nrows(), 5); // 5 volumes
    assert_eq!(pca_result.components.ncols(), 2); // 2 components

    // Check explained variance
    assert_eq!(pca_result.explained_variance.len(), 2);
    assert_eq!(pca_result.explained_variance_ratio.len(), 2);

    // Variance ratios should sum to <= 1.0
    let total_variance: f64 = pca_result.explained_variance_ratio.iter().sum();
    assert!(total_variance <= 1.0 + 1e-6);

    // First component should explain more variance than second
    assert!(pca_result.explained_variance_ratio[0] >= pca_result.explained_variance_ratio[1]);
}

