//! Event file reading and processing
//!
//! This module provides functionality for reading BIDS event files (.tsv format)
//! and processing trial-by-trial experimental data.

use std::collections::HashMap;
use std::path::Path;
use csv::ReaderBuilder;
use serde::{Deserialize, Serialize};

use crate::error::{BidsError, Result};
use crate::file::BidsFile;
use crate::io::utils;
use super::BidsReader;

/// Event data structure
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct EventData {
    /// Event onset times (in seconds)
    pub onset: Vec<f64>,
    /// Event durations (in seconds)
    pub duration: Vec<f64>,
    /// Trial types or event labels
    pub trial_type: Vec<String>,
    /// Additional event columns
    pub additional_columns: HashMap<String, Vec<String>>,
}

/// Individual event record
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct EventRecord {
    /// Event onset time (in seconds)
    pub onset: f64,
    /// Event duration (in seconds)
    pub duration: f64,
    /// Trial type or event label
    pub trial_type: String,
    /// Additional event data
    pub additional_data: HashMap<String, String>,
}

/// Event file reader
pub struct EventsReader {
    /// Column delimiter (default: tab)
    delimiter: u8,
    /// Whether to include additional columns
    include_additional: bool,
}

impl EventsReader {
    /// Create a new events reader
    pub fn new() -> Self {
        Self {
            delimiter: b'\t',
            include_additional: true,
        }
    }

    /// Set the column delimiter
    pub fn delimiter(mut self, delimiter: u8) -> Self {
        self.delimiter = delimiter;
        self
    }

    /// Set whether to include additional columns
    pub fn include_additional(mut self, include: bool) -> Self {
        self.include_additional = include;
        self
    }

    /// Read events from a CSV reader
    fn read_from_reader<R: std::io::Read>(&self, reader: R) -> Result<EventData> {
        let mut csv_reader = ReaderBuilder::new()
            .delimiter(self.delimiter)
            .has_headers(true)
            .from_reader(reader);

        let headers = csv_reader.headers()?.clone();

        // Find required columns
        let onset_col = headers.iter().position(|h| h == "onset")
            .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing 'onset' column"))?;

        let duration_col = headers.iter().position(|h| h == "duration")
            .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing 'duration' column"))?;

        let trial_type_col = headers.iter().position(|h| h == "trial_type");

        // Initialize vectors
        let mut onset = Vec::new();
        let mut duration = Vec::new();
        let mut trial_type = Vec::new();
        let mut additional_columns: HashMap<String, Vec<String>> = HashMap::new();

        // Initialize additional columns
        if self.include_additional {
            for (i, header) in headers.iter().enumerate() {
                if i != onset_col && i != duration_col && Some(i) != trial_type_col {
                    additional_columns.insert(header.to_string(), Vec::new());
                }
            }
        }

        // Read records
        for result in csv_reader.records() {
            let record = result?;

            // Parse onset
            let onset_str = record.get(onset_col)
                .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing onset value"))?;
            let onset_val = onset_str.parse::<f64>()
                .map_err(|_| BidsError::parse_error("events.tsv", "Invalid onset value"))?;
            onset.push(onset_val);

            // Parse duration
            let duration_str = record.get(duration_col)
                .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing duration value"))?;
            let duration_val = duration_str.parse::<f64>()
                .map_err(|_| BidsError::parse_error("events.tsv", "Invalid duration value"))?;
            duration.push(duration_val);

            // Parse trial_type
            let trial_type_val = if let Some(col) = trial_type_col {
                record.get(col)
                    .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing trial_type value"))?
                    .to_string()
            } else {
                "n/a".to_string()
            };
            trial_type.push(trial_type_val);

            // Parse additional columns
            if self.include_additional {
                for (i, value) in record.iter().enumerate() {
                    if i != onset_col && i != duration_col && Some(i) != trial_type_col {
                        let header = &headers[i];
                        if let Some(col_vec) = additional_columns.get_mut(header) {
                            col_vec.push(value.to_string());
                        }
                    }
                }
            }
        }

        Ok(EventData {
            onset,
            duration,
            trial_type,
            additional_columns,
        })
    }

    /// Convert EventData to individual records
    pub fn to_records(&self, data: &EventData) -> Vec<EventRecord> {
        let mut records = Vec::new();

        for i in 0..data.onset.len() {
            let mut additional_data = HashMap::new();

            // Collect additional data for this record
            for (col_name, col_values) in &data.additional_columns {
                if let Some(value) = col_values.get(i) {
                    additional_data.insert(col_name.clone(), value.clone());
                }
            }

            records.push(EventRecord {
                onset: data.onset[i],
                duration: data.duration[i],
                trial_type: data.trial_type[i].clone(),
                additional_data,
            });
        }

        records
    }
}

impl Default for EventsReader {
    fn default() -> Self {
        Self::new()
    }
}

impl BidsReader<EventData> for EventsReader {
    fn read(&self, file: &BidsFile) -> Result<EventData> {
        if !file.is_events() {
            return Err(BidsError::validation_error(
                "File is not an events file",
                Some("suffix".to_string()),
            ));
        }

        self.read_path(&file.path)
    }

    fn read_path(&self, path: &Path) -> Result<EventData> {
        if !utils::is_readable(path) {
            return Err(BidsError::file_not_found(path));
        }

        let file = std::fs::File::open(path)?;
        self.read_from_reader(file)
    }
}

impl EventData {
    /// Create a new empty EventData
    pub fn new() -> Self {
        Self {
            onset: Vec::new(),
            duration: Vec::new(),
            trial_type: Vec::new(),
            additional_columns: HashMap::new(),
        }
    }

    /// Get the number of events
    pub fn len(&self) -> usize {
        self.onset.len()
    }

    /// Check if the event data is empty
    pub fn is_empty(&self) -> bool {
        self.onset.is_empty()
    }

    /// Get unique trial types
    pub fn unique_trial_types(&self) -> Vec<String> {
        let mut types: Vec<String> = self.trial_type.iter().cloned().collect();
        types.sort();
        types.dedup();
        types
    }

    /// Filter events by trial type
    pub fn filter_by_trial_type(&self, trial_type: &str) -> Self {
        let mut filtered = EventData::new();

        for (i, t_type) in self.trial_type.iter().enumerate() {
            if t_type == trial_type {
                filtered.onset.push(self.onset[i]);
                filtered.duration.push(self.duration[i]);
                filtered.trial_type.push(t_type.clone());

                // Copy additional columns
                for (col_name, col_values) in &self.additional_columns {
                    if let Some(value) = col_values.get(i) {
                        filtered.additional_columns
                            .entry(col_name.clone())
                            .or_insert_with(Vec::new)
                            .push(value.clone());
                    }
                }
            }
        }

        filtered
    }

    /// Get events within a time range
    pub fn filter_by_time_range(&self, start: f64, end: f64) -> Self {
        let mut filtered = EventData::new();

        for (i, &onset) in self.onset.iter().enumerate() {
            if onset >= start && onset <= end {
                filtered.onset.push(onset);
                filtered.duration.push(self.duration[i]);
                filtered.trial_type.push(self.trial_type[i].clone());

                // Copy additional columns
                for (col_name, col_values) in &self.additional_columns {
                    if let Some(value) = col_values.get(i) {
                        filtered.additional_columns
                            .entry(col_name.clone())
                            .or_insert_with(Vec::new)
                            .push(value.clone());
                    }
                }
            }
        }

        filtered
    }

    /// Get summary statistics
    pub fn summary(&self) -> EventSummary {
        let n_events = self.len();
        let unique_types = self.unique_trial_types();

        let total_duration = self.duration.iter().sum();
        let min_duration = self.duration.iter().fold(f64::INFINITY, |a, &b| a.min(b));
        let max_duration = self.duration.iter().fold(f64::NEG_INFINITY, |a, &b| a.max(b));
        let mean_duration = if n_events > 0 { total_duration / n_events as f64 } else { 0.0 };

        let min_onset = self.onset.iter().fold(f64::INFINITY, |a, &b| a.min(b));
        let max_onset = self.onset.iter().fold(f64::NEG_INFINITY, |a, &b| a.max(b));

        EventSummary {
            n_events,
            n_trial_types: unique_types.len(),
            trial_types: unique_types,
            total_duration,
            mean_duration,
            min_duration,
            max_duration,
            min_onset,
            max_onset,
        }
    }
}

impl Default for EventData {
    fn default() -> Self {
        Self::new()
    }
}

/// Summary statistics for event data
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct EventSummary {
    /// Number of events
    pub n_events: usize,
    /// Number of unique trial types
    pub n_trial_types: usize,
    /// List of trial types
    pub trial_types: Vec<String>,
    /// Total duration of all events
    pub total_duration: f64,
    /// Mean event duration
    pub mean_duration: f64,
    /// Minimum event duration
    pub min_duration: f64,
    /// Maximum event duration
    pub max_duration: f64,
    /// Minimum onset time
    pub min_onset: f64,
    /// Maximum onset time
    pub max_onset: f64,
}

impl std::fmt::Display for EventSummary {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        writeln!(f, "Event Summary")?;
        writeln!(f, "Events: {}", self.n_events)?;
        writeln!(f, "Trial Types: {}", self.n_trial_types)?;
        writeln!(f, "Types: {}", self.trial_types.join(", "))?;
        writeln!(f, "Duration: {:.3} - {:.3} (mean: {:.3})", 
                 self.min_duration, self.max_duration, self.mean_duration)?;
        writeln!(f, "Onset Range: {:.3} - {:.3}", self.min_onset, self.max_onset)?;
        Ok(())
    }
}

/// Convenience function to read events from a path
pub fn read_events<P: AsRef<Path>>(path: P) -> Result<EventData> {
    let reader = EventsReader::new();
    reader.read_path(path.as_ref())
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;
    use std::fs;

    fn create_test_events_file() -> Result<(TempDir, std::path::PathBuf)> {
        let temp_dir = TempDir::new()?;
        let file_path = temp_dir.path().join("sub-01_task-test_events.tsv");

        let content = "onset\tduration\ttrial_type\tresponse\n\
                       0.0\t2.0\tgolden\t1\n\
                       5.0\t2.0\tgolden\t1\n\
                       10.0\t2.0\tscrambled\t0\n\
                       15.0\t2.0\tscrambled\t0\n";

        fs::write(&file_path, content)?;
        Ok((temp_dir, file_path))
    }

    #[test]
    fn test_read_events_file() -> Result<()> {
        let (_temp_dir, file_path) = create_test_events_file()?;

        let events = read_events(&file_path)?;

        assert_eq!(events.len(), 4);
        assert_eq!(events.onset, vec![0.0, 5.0, 10.0, 15.0]);
        assert_eq!(events.duration, vec![2.0, 2.0, 2.0, 2.0]);
        assert_eq!(events.trial_type, vec!["golden", "golden", "scrambled", "scrambled"]);
        assert!(events.additional_columns.contains_key("response"));

        Ok(())
    }

    #[test]
    fn test_events_reader_configuration() -> Result<()> {
        let (_temp_dir, file_path) = create_test_events_file()?;

        let reader = EventsReader::new()
            .delimiter(b'\t')
            .include_additional(false);

        let events = reader.read_path(&file_path)?;

        assert_eq!(events.len(), 4);
        assert!(events.additional_columns.is_empty());

        Ok(())
    }

    #[test]
    fn test_event_data_filtering() -> Result<()> {
        let (_temp_dir, file_path) = create_test_events_file()?;
        let events = read_events(&file_path)?;

        // Filter by trial type
        let golden_events = events.filter_by_trial_type("golden");
        assert_eq!(golden_events.len(), 2);
        assert_eq!(golden_events.trial_type, vec!["golden", "golden"]);

        // Filter by time range
        let early_events = events.filter_by_time_range(0.0, 10.0);
        assert_eq!(early_events.len(), 3);

        Ok(())
    }

    #[test]
    fn test_event_summary() -> Result<()> {
        let (_temp_dir, file_path) = create_test_events_file()?;
        let events = read_events(&file_path)?;

        let summary = events.summary();

        assert_eq!(summary.n_events, 4);
        assert_eq!(summary.n_trial_types, 2);
        assert_eq!(summary.trial_types, vec!["golden", "scrambled"]);
        assert_eq!(summary.total_duration, 8.0);
        assert_eq!(summary.mean_duration, 2.0);
        assert_eq!(summary.min_onset, 0.0);
        assert_eq!(summary.max_onset, 15.0);

        Ok(())
    }

    #[test]
    fn test_to_records() -> Result<()> {
        let (_temp_dir, file_path) = create_test_events_file()?;
        let events = read_events(&file_path)?;

        let reader = EventsReader::new();
        let records = reader.to_records(&events);

        assert_eq!(records.len(), 4);
        assert_eq!(records[0].onset, 0.0);
        assert_eq!(records[0].trial_type, "golden");
        assert_eq!(records[0].additional_data.get("response"), Some(&"1".to_string()));

        Ok(())
    }

    #[test]
    fn test_unique_trial_types() -> Result<()> {
        let (_temp_dir, file_path) = create_test_events_file()?;
        let events = read_events(&file_path)?;

        let unique_types = events.unique_trial_types();
        assert_eq!(unique_types, vec!["golden", "scrambled"]);

        Ok(())
    }

    #[test]
    fn test_invalid_events_file() {
        let temp_dir = TempDir::new().unwrap();
        let file_path = temp_dir.path().join("invalid_events.tsv");

        // Missing required columns
        let content = "trial_type\tresponse\n\
                       golden\t1\n\
                       scrambled\t0\n";

        fs::write(&file_path, content).unwrap();

        let result = read_events(&file_path);
        assert!(result.is_err());
    }
}

